function thoughtProfitLabel(item){const rate=item.thesis_win_rate?.rate??0;if(item.trade_side==='观察')return `<span>思路胜率 ${rate}%</span>`;if(item.trade_status==='已平仓')return `<span class="${changeClass(item.realized_profit_pct)}">已实现 ${thoughtPercent(item.realized_profit_pct)}</span>`;if(item.profit_pct!==null&&item.profit_pct!==undefined)return `<span class="${changeClass(item.profit_pct)}">浮盈 ${thoughtPercent(item.profit_pct)}</span>`;return `<span>思路胜率 ${rate}%</span>`}
