function tradeChart(plan){
  const candles=plan.candles||[];
  if(candles.length<2)return '<div class="trade-chart-empty">暂无足够 K 线缓存</div>';
  const entry=Number(plan.entry_price),stop=Number(plan.stop_price),tp1=Number(plan.take_profit_1),tp2=Number(plan.take_profit_2),current=Number(plan.current_price);
  const levels=[entry,stop,tp1,tp2,current],prices=candles.flatMap(c=>[c.high,c.low,c.open,c.close]).concat(levels).map(Number).filter(Number.isFinite);
  const min=Math.min(...prices)*.996,max=Math.max(...prices)*1.004;
  const candleStep=12,candleBody=7,w=Math.max(1280,candles.length*candleStep+170),h=460,m={l:18,r:94,t:28,b:34},priceH=310,volumeTop=356,volumeH=66,iw=w-m.l-m.r;
  const x=i=>m.l+i*candleStep+8,y=p=>m.t+(max-p)*priceH/(max-min),volMax=Math.max(...candles.map(c=>Number(c.volume)||0),1);
  const gridPrices=Array.from({length:6},(_,i)=>min+(max-min)*i/5).reverse();
  const grid=gridPrices.map(p=>`<line x1="${m.l}" x2="${w-m.r}" y1="${y(p)}" y2="${y(p)}" class="tv-grid"/><text x="${w-m.r+8}" y="${y(p)+4}" class="tv-axis">${tradePrice(p)}</text>`).join('')+
    Array.from({length:Math.floor(candles.length/24)+1},(_,i)=>i*24).filter(i=>i<candles.length).map(i=>`<line x1="${x(i)}" x2="${x(i)}" y1="${m.t}" y2="${volumeTop+volumeH}" class="tv-grid vertical"/><text x="${x(i)-18}" y="${h-12}" class="tv-time">${candles[i].time}</text>`).join('');
  const bodies=candles.map((c,i)=>{const up=Number(c.close)>=Number(c.open),cx=x(i),top=y(Math.max(c.open,c.close)),height=Math.max(1.5,Math.abs(y(c.open)-y(c.close))),vy=volumeTop+volumeH-(Number(c.volume)||0)/volMax*volumeH;return `<line x1="${cx}" x2="${cx}" y1="${y(c.high)}" y2="${y(c.low)}" class="${up?'tv-up':'tv-down'}"/><rect x="${cx-candleBody/2}" y="${top}" width="${candleBody}" height="${height}" rx="1" class="${up?'tv-up':'tv-down'}"/><rect x="${cx-candleBody/2}" y="${vy}" width="${candleBody}" height="${volumeTop+volumeH-vy}" class="${up?'tv-vol-up':'tv-vol-down'}"/>`}).join('');
  const isShort=plan.direction==='short',touch=(price,from=0,mode='any')=>{const p=Number(price);for(let i=Math.max(0,from);i<candles.length;i++){const c=candles[i];if(mode==='long-up'&&Number(c.high)>=p)return i;if(mode==='long-down'&&Number(c.low)<=p)return i;if(mode==='short-down'&&Number(c.low)<=p)return i;if(mode==='short-up'&&Number(c.high)>=p)return i;if(mode==='any'&&Number(c.low)<=p&&Number(c.high)>=p)return i}return -1};
  const entryIdx=touch(entry,0,isShort?'short-down':'long-up'),start=entryIdx>=0?entryIdx:0,tp1Idx=touch(tp1,start,isShort?'short-down':'long-up'),tp2Idx=touch(tp2,start,isShort?'short-down':'long-up'),stopIdx=touch(stop,start,isShort?'short-up':'long-down');
  const priceLine=(price,cls,label)=>Number.isFinite(Number(price))?`<line x1="${m.l}" x2="${w-m.r}" y1="${y(price)}" y2="${y(price)}" class="${cls}"/><text x="${w-m.r+8}" y="${y(price)+4}" class="tv-level-label">${label} ${tradePrice(price)}</text>`:'';
  const marker=(idx,price,cls,label)=>idx>=0?`<g class="trade-point ${cls}" transform="translate(${x(idx)},${y(price)})"><path d="M0,-10 L9,0 L0,10 L-9,0 Z"/><text x="12" y="-9">${label}</text></g>`:'';
  const currentLine=Number.isFinite(current)?`<line x1="${m.l}" x2="${w-m.r}" y1="${y(current)}" y2="${y(current)}" class="tv-current-line"/><rect x="${w-m.r+4}" y="${y(current)-13}" width="78" height="24" rx="3" class="${current>=Number(candles[candles.length-1].open)?'tv-price-tag up':'tv-price-tag down'}"/><text x="${w-m.r+9}" y="${y(current)+4}" class="tv-price-text">${tradePrice(current)}</text>`:'';
  return `<div class="trade-chart-shell"><div class="trade-chart-topbar"><span>${plan.symbol} · 5m · Binance</span><div class="trade-chart-legend"><b class="entry">入场线</b><b class="tp">止盈线</b><b class="stop">止损线</b><b class="current">现价线</b></div></div><div class="trade-chart-scroll tv-scroll" aria-label="${plan.symbol} K线可横向滑动"><svg class="trade-chart tv-chart" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}" role="img" aria-label="${plan.symbol} 趋势验证K线图"><rect x="0" y="0" width="${w}" height="${h}" class="tv-bg"/><rect x="${m.l}" y="${m.t}" width="${iw}" height="${priceH}" class="tv-panel"/><rect x="${m.l}" y="${volumeTop}" width="${iw}" height="${volumeH}" class="tv-volume-panel"/>${grid}<text x="${m.l}" y="${volumeTop-9}" class="tv-volume-title">Volume</text>${bodies}${priceLine(entry,'entry-line','入场')}${priceLine(tp1,'tp-line','止盈1')}${priceLine(tp2,'tp-line','止盈2')}${priceLine(stop,'stop-line','止损')}${currentLine}${marker(entryIdx,entry,'buy','买入')}${marker(tp1Idx,tp1,'sell','卖出1')}${marker(tp2Idx,tp2,'sell','卖出2')}${marker(stopIdx,stop,'stop','止损')}</svg></div><input class="trade-chart-range" type="range" min="0" max="0" value="0" aria-label="拖动查看前后K线"></div>`;
}
function tradePlanCard(plan){const pnl=Number(plan.pnl||0),key=plan.id||plan.symbol,signature=(plan.candles||[]).map(c=>`${c.time}:${c.open}:${c.high}:${c.low}:${c.close}`).join('|');return `<article class="trade-plan-card ${plan.direction} ${plan.status}" data-plan-key="${key}" data-chart-signature="${signature}"><div class="trade-plan-head"><div><p class="eyebrow">SINGLE TRADE VALIDATION</p><h3>${plan.symbol} <span class="${plan.direction}">${tradeDirectionLabel(plan.direction)}</span></h3><small>${tradeStatusLabel(plan.status)} · 100U · ${plan.leverage}倍 · 暂无手续费</small></div><div class="trade-plan-pnl ${tradePnlClass(pnl)}"><span>${plan.status==='planned'?'计划盈亏':'当前盈亏'}</span><b>${pnl>=0?'+':''}${pnl.toFixed(2)}U</b></div></div><div class="trade-level-grid"><span>当前价<b>${tradePrice(plan.current_price)}</b></span><span>入场<b>${tradePrice(plan.entry_price)}</b></span><span>止损<b>${tradePrice(plan.stop_price)}</b></span><span>止盈1<b>${tradePrice(plan.take_profit_1)}</b></span><span>止盈2<b>${tradePrice(plan.take_profit_2)}</b></span></div>${tradeChart(plan)}<p class="trade-thesis">${plan.thesis||''}</p><div class="trade-plan-foot"><span>开仓：${plan.opened_at||'未触发'}</span><span>平仓：${plan.closed_at||'--'}</span><span>退出：${plan.exit_reason||'--'} ${plan.exit_price?tradePrice(plan.exit_price):''}</span></div></article>`}
function tradeValidationSummaryHtml(s={}){const rate=s.win_rate===null||s.win_rate===undefined?'--':`${Number(s.win_rate).toFixed(1)}%`,pnl=Number(s.total_pnl||0);return `<article><p>总计划</p><strong>${s.total||0}</strong><small>一笔一笔验证</small></article><article><p>胜率</p><strong>${rate}</strong><small>只统计已结算</small></article><article><p>总盈亏</p><strong class="${tradePnlClass(pnl)}">${pnl>=0?'+':''}${pnl.toFixed(2)}U</strong><small>100U / 1倍 / 无手续费</small></article>`}
function activateTradeChartScrolls(root=document){
  root.querySelectorAll('.trade-chart-scroll').forEach(scroller=>{
    const shell=scroller.closest('.trade-chart-shell'),range=shell?.querySelector('.trade-chart-range');
    if(!scroller.dataset.chartReady){
      scroller.dataset.chartReady='1';
      scroller.scrollLeft=scroller.scrollWidth;
    }
    if(range&&!range.dataset.rangeReady){
      const syncRange=()=>{range.max=Math.max(0,scroller.scrollWidth-scroller.clientWidth);range.value=scroller.scrollLeft};
      range.dataset.rangeReady='1';
      range.addEventListener('input',()=>{scroller.scrollLeft=Number(range.value)||0});
      scroller.addEventListener('scroll',syncRange,{passive:true});
      setTimeout(syncRange,0);
    }else if(range){
      range.max=Math.max(0,scroller.scrollWidth-scroller.clientWidth);
      range.value=scroller.scrollLeft;
    }
  });
}
function renderTradeValidation(target,data){const plans=data.plans||[];if(target.dataset.loaded!=='1'){target.dataset.loaded='1';target.innerHTML=`<div class="trade-validation-summary">${tradeValidationSummaryHtml(data.summary||{})}</div><div class="trade-plan-list">${plans.length?plans.map(tradePlanCard).join(''):'<p class="empty-alert">暂无趋势验证计划。</p>'}</div>`;activateTradeChartScrolls(target);return}let summary=target.querySelector('.trade-validation-summary'),list=target.querySelector('.trade-plan-list');if(!summary){target.insertAdjacentHTML('afterbegin','<div class="trade-validation-summary"></div>');summary=target.querySelector('.trade-validation-summary')}if(!list){target.insertAdjacentHTML('beforeend','<div class="trade-plan-list"></div>');list=target.querySelector('.trade-plan-list')}summary.innerHTML=tradeValidationSummaryHtml(data.summary||{});if(!plans.length){list.innerHTML='<p class="empty-alert">暂无趋势验证计划。</p>';return}const seen=new Set();plans.forEach(plan=>{const key=String(plan.id||plan.symbol);seen.add(key);const wrap=document.createElement('div');wrap.innerHTML=tradePlanCard(plan);const fresh=wrap.firstElementChild,old=list.querySelector(`[data-plan-key="${CSS.escape(key)}"]`);if(!old){list.appendChild(fresh);activateTradeChartScrolls(fresh);return}const oldScroll=old.querySelector('.trade-chart-scroll'),oldLeft=oldScroll?oldScroll.scrollLeft:0,oldSignature=old.dataset.chartSignature,newSignature=fresh.dataset.chartSignature;if(oldSignature===newSignature){const chart=old.querySelector('.trade-chart-scroll');fresh.querySelector('.trade-chart-scroll')?.replaceWith(chart)}old.replaceWith(fresh);const nextScroll=fresh.querySelector('.trade-chart-scroll');if(nextScroll)nextScroll.scrollLeft=oldLeft});list.querySelectorAll('.trade-plan-card[data-plan-key]').forEach(card=>{if(!seen.has(card.dataset.planKey))card.remove()});activateTradeChartScrolls(target)}
async function loadTradeValidation(){const target=byId('tradeValidation');if(!target)return;const hasOld=target.dataset.loaded==='1';if(!hasOld)target.innerHTML='<p class="loading">正在读取趋势验证记录…</p>';else target.classList.add('soft-loading');try{const data=await (await fetch('/api/trade-validation')).json();renderTradeValidation(target,data)}catch(error){if(!hasOld)target.innerHTML='<p class="empty-alert">趋势验证暂时无法读取。</p>'}finally{target.classList.remove('soft-loading')}}
document.querySelectorAll('nav a[data-view="daily-thoughts"]').forEach(link=>link.addEventListener('click',()=>loadThoughtAnalysis()));
document.querySelectorAll('nav a[data-view="trade-validation"]').forEach(link=>link.addEventListener('click',()=>loadTradeValidation()));
let tradeChartDrag=null;
function tradeChartDragStart(scroller,clientX){tradeChartDrag={scroller,startX:clientX,startLeft:scroller.scrollLeft};scroller.classList.add('dragging')}
function tradeChartDragMove(clientX){if(!tradeChartDrag)return;tradeChartDrag.scroller.scrollLeft=tradeChartDrag.startLeft-(clientX-tradeChartDrag.startX)}
function tradeChartDragEnd(){if(!tradeChartDrag)return;tradeChartDrag.scroller.classList.remove('dragging');tradeChartDrag=null}
document.addEventListener('mousedown',event=>{const scroller=event.target.closest?.('.trade-chart-scroll');if(!scroller||event.button!==0)return;event.preventDefault();tradeChartDragStart(scroller,event.clientX)});
document.addEventListener('mousemove',event=>tradeChartDragMove(event.clientX));
document.addEventListener('mouseup',tradeChartDragEnd);
document.addEventListener('mouseleave',tradeChartDragEnd);
document.addEventListener('touchstart',event=>{const scroller=event.target.closest?.('.trade-chart-scroll');if(!scroller||!event.touches.length)return;tradeChartDragStart(scroller,event.touches[0].clientX)},{passive:true});
document.addEventListener('touchmove',event=>{if(!tradeChartDrag||!event.touches.length)return;event.preventDefault();tradeChartDragMove(event.touches[0].clientX)},{passive:false});
document.addEventListener('touchend',tradeChartDragEnd);
document.addEventListener('wheel',event=>{const scroller=event.target.closest?.('.trade-chart-scroll');if(!scroller)return;if(Math.abs(event.deltaY)>Math.abs(event.deltaX)){event.preventDefault();scroller.scrollLeft+=event.deltaY}else scroller.scrollLeft+=event.deltaX},{passive:false});
updateSidebarSubnav(document.querySelector('.view.active')?.id||'dashboard');renderGainersShell();renderDualFuturesShell();addDualLiquidityHeader();addDualBasisSortControls();addBasisOpeningHeaders();installGroupFrameObservers();updateAlarmSoundButton();updateSortHeaders();updateDualSortHeaders();loadDashboard();loadStrategies();loadSpotFutures();loadDualFutures();loadAlerts(true);loadSimpleThinking();loadFundingTrend();loadTradeValidation();loadThoughtAnalysis();loadTokenHedgeProfiles();setInterval(loadDashboard,5000);setInterval(loadSpotFutures,5000);setInterval(loadDualFutures,5000);setInterval(loadAlerts,5000);setInterval(loadSimpleThinking,30000);setInterval(loadFundingTrend,60000);setInterval(loadTradeValidation,30000);setInterval(loadThoughtAnalysis,300000);
document.addEventListener('click',event=>{if(event.target.id==='symbolDetailModal')closeSymbolDetail()});
